async function ensureDir(dir: string) {
  try {
    await fsp.mkdir(dir, { recursive: true });
  } catch (e) {
    // ignore if exists
  }
}

async function readJson<T>(file: string, defaultVal: T): Promise<T> {
  try {
    const data = await fsp.readFile(file, 'utf-8');
    if (!data.trim()) return defaultVal;
    return JSON.parse(data);
  } catch (e) {
    return defaultVal;
  }
}

async function writeJson(file: string, data: any) {
  await ensureDir(path.dirname(file));
  await fsp.writeFile(file, JSON.stringify(data, null, 2), 'utf-8');
}

export async function seedDefaults() {
  const currentTemplates = await getTemplates();
  let changed = false;

  for (const def of DEFAULT_TEMPLATES) {
      const idx = currentTemplates.findIndex(t => t.id === def.id);

      if (idx === -1) {
          // Add new default
          currentTemplates.push(def);
          changed = true;
      } else {
          // Update existing default if core selectors changed
          const existing = currentTemplates[idx];
          if (existing.contentSelector !== def.contentSelector || existing.titleSelector !== def.titleSelector) {
             console.log(`[Storage] Updating default protocol definition for: ${def.domain}`);
             currentTemplates[idx] = {
                 ...existing,
                 titleSelector: def.titleSelector,
                 contentSelector: def.contentSelector,
                 removeSelectors: def.removeSelectors,
                 updatedAt: Date.now()
             };
             changed = true;
          }
      }
  }

  if (changed) {
      await saveTemplates(currentTemplates);
      console.log('Seeded/Updated default protocols.');
      return true;
  }
  return false;
}

export async function initStorage() {
  await ensureDir(DATA_DIR);
  await seedDefaults();
}

export async function getSettings(): Promise<AppSettings> {
  const loaded = await readJson<Partial<AppSettings>>(SETTINGS_FILE, {});
  return { ...DEFAULT_SETTINGS, ...loaded };
}

export async function saveSettings(settings: AppSettings) {
  await writeJson(SETTINGS_FILE, settings);
}

export async function getTemplates(): Promise<ProtocolTemplate[]> {
  return readJson<ProtocolTemplate[]>(TEMPLATES_FILE, []);
}

export async function saveTemplates(templates: ProtocolTemplate[]) {
  await writeJson(TEMPLATES_FILE, templates);
}

import * as cheerio from 'cheerio';
import { chromium } from 'playwright';
import { normalizeHost } from './domain.ts';
import type { ProtocolTemplate, DiagnosticResult, AppSettings } from '../types.ts';

// Common User Agent to use across fetch and playwright
const DEFAULT_USER_AGENT = 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/124.0.0.0 Safari/537.36';

// Magic token for line breaks
const BR_TOKEN = '[[__BR__]]';

// Standardized cleanup function
function cleanText(text: string): string {
  if (!text) return '';

  // 1. Replace newlines/tabs with space (standard HTML behavior)
  let t = text.replace(/[\r\n\t]+/g, ' ');

  // 2. Collapse multiple spaces
  t = t.replace(/\s+/g, ' ');

  // 3. Restore explicit line breaks
  t = t.split(BR_TOKEN).join('\n');

  // 4. Trim and remove odd artifacts
  return t.trim();
}

/**
 * Intelligent Header Trimming
 * Removes Titles, Dates, Author Names, and Metadata from the start of the content array.
 */
function cleanupHeader(paras: string[], title: string): string[] {
    let lines = [...paras];
    const t = cleanText(title).toLowerCase();

    // Safety: Only check the top few lines to avoid eating the story
    let checkLimit = 8;

    while (lines.length > 0 && checkLimit > 0) {
        checkLimit--;
        const line = cleanText(lines[0]);
        const lowLine = line.toLowerCase();

        // 1. Title Match (Exact, Fuzzy, or Contained)
        // matches: "Chapter 4" vs "Path of Dragons - Chapter 4"
        const isTitle = lowLine === t 
            || (t.length > 5 && lowLine.includes(t)) 
            || (lowLine.length > 5 && t.includes(lowLine));

        if (isTitle) {
            lines.shift();
            continue; // Keep checking next line
        }

        // 2. Date Detection
        // Matches: Apr 13, 2024 | 13 Apr 2024 | 2024-04-13
        // Also matches repeating dates which happens often on Patreon
        const isDate = /(?:jan|feb|mar|apr|may|jun|jul|aug|sep|oct|nov|dec)[a-z]*[\s,.]+\d{1,2}(?:st|nd|rd|th)?[\s,.]+\d{4}/i.test(line)
            || /\d{4}[\-./]\d{2}[\-./]\d{2}/.test(line);

        if (isDate) {
            lines.shift();
            continue;
        }

        // 3. Metadata/Author Detection
        // Heuristic: 
        // - Short (< 60 chars)
        // - No sentence ending punctuation (. ! ?)
        // - Not a dialogue line (doesn't start/end with quotes)
        // - Contains letters
        // This targets "Nicholas R Searcy" or "Doing Things Right"
        const isMetadata = line.length < 60 
            && !/[.!?]["']?$/.test(line)  // Ends with punctuation (optional quote)
            && !/^["“'‘]/.test(line)      // Starts with quote
            && /[a-z]/i.test(line)        // Has letters
            && !line.includes('“')        // Safety: Dialogue quotes inside
            && !line.includes('"');       // Safety: Dialogue quotes inside

        if (isMetadata) {
            lines.shift();
            continue;
        }

        // 4. Explicit "Posted by"
        if (/^(posted|written|published) by/i.test(line)) {
            lines.shift();
            continue;
        }

        // If nothing matched, we assume we hit the body.
        break;
    }

    return lines;
}

/**
 * Intelligent Footer Trimming
 * Mirrored logic of cleanupHeader but operates from the bottom up.
 * Crucial because deduplication often fails if the header instance was removed.
 */
function cleanupFooter(paras: string[], title: string): string[] {
    let lines = [...paras];
    const t = cleanText(title).toLowerCase();

    // Safety: Only check the bottom few lines
    let checkLimit = 10;

    while (lines.length > 0 && checkLimit > 0) {
        checkLimit--;
        const lastIndex = lines.length - 1;
        const line = cleanText(lines[lastIndex]);
        const lowLine = line.toLowerCase();

        // 1. Title Match
        const isTitle = lowLine === t 
            || (t.length > 5 && lowLine.includes(t)) 
            || (lowLine.length > 5 && t.includes(lowLine));

        if (isTitle) {
            lines.pop();
            continue;
        }

        // 2. Date Detection
        const isDate = /(?:jan|feb|mar|apr|may|jun|jul|aug|sep|oct|nov|dec)[a-z]*[\s,.]+\d{1,2}(?:st|nd|rd|th)?[\s,.]+\d{4}/i.test(line)
            || /\d{4}[\-./]\d{2}[\-./]\d{2}/.test(line);

        if (isDate) {
            lines.pop();
            continue;
        }

        // 3. Metadata/Author Detection
        const isMetadata = line.length < 60 
            && !/[.!?]["']?$/.test(line)
            && !/^["“'‘]/.test(line)
            && /[a-z]/i.test(line)
            && !line.includes('“') 
            && !line.includes('"');

        if (isMetadata) {
            lines.pop();
            continue;
        }

        // 4. Navigation/Social keywords
        if (/^(next|previous|prev) (chapter|part|episode)|(share|like|comment)/i.test(line)) {
            lines.pop();
            continue;
        }

        break;
    }

    return lines;
}

/**
 * Advanced Deduplication Strategy
 * 1. Neighbor Stutter: Remove immediate duplicates.
 * 2. Global Long Line: Remove repeated long paragraphs (likely preview text).
 * 3. Tail Trimming: Remove lines from the END if they appear earlier (likely comments/metadata/nav).
 */
function deduplicateLines(text: string): string {
    let lines = text.split('\n').map(l => l.trim());

    // --- Phase 1: Neighbor Stutter Removal ---
    // Handles: "Date", "Date" -> "Date"
    lines = lines.filter((line, i) => {
        if (!line) return i === 0 || lines[i-1] !== ''; // Preserve structural spacing (max 1 empty line)
        return i === 0 || line !== lines[i-1];
    });

    // --- Phase 2: Global Long-Paragraph Deduplication ---
    // Handles: "Preview text..." appearing in body and then again later.
    const seenLong = new Set<string>();
    const filteredBody: string[] = [];

    for (const line of lines) {
        if (!line) {
            filteredBody.push(line);
            continue;
        }

        // If line is substantial (> 30 chars), ensure it's globally unique
        if (line.length > 30) {
            if (seenLong.has(line)) continue; 
            seenLong.add(line);
        }

        filteredBody.push(line);
    }
    lines = filteredBody;

    // --- Phase 3: Smart Tail Trimming ---
    // Handles: Comments/Quotes at the bottom that are copies of text from above.
    // Logic: Iterate backwards. If a line exists elsewhere in the doc, cut it. Stop at first unique line.

    // Build frequency map for the current state
    const frequency = new Map<string, number>();
    for (const line of lines) {
        if (line.length < 2) continue; // Ignore tiny punctuation
        frequency.set(line, (frequency.get(line) || 0) + 1);
    }

    let endIndex = lines.length - 1;
    let cutCount = 0;

    while (endIndex >= 0) {
        const line = lines[endIndex];

        // Skip empty lines at the very bottom
        if (!line) {
            endIndex--;
            continue;
        }

        const count = frequency.get(line) || 1;

        // If this line appears more than once (meaning it's here AND somewhere else),
        // we assume it's footer junk (metadata, nav, quoted comment).
        if (count > 1) {
            endIndex--;
            cutCount++;
        } else {
            // We hit a unique line! This is likely the true end of the story.
            break; 
        }
    }

    // Safety: If we are about to cut > 50% of the content, something is wrong (maybe a refrain poem?). 
    // Abort tail trim in that extreme case.
    if (cutCount < lines.length * 0.5) {
        lines = lines.slice(0, endIndex + 1);
    }

    return lines.join('\n');
}

function postProcessBody(body: string): string {
    const deduped = deduplicateLines(body);
    return deduped
        .replace(/\n{3,}/g, '\n\n') // Collapse 3+ newlines
        .trim();
}

// --- Visual Formatting Helpers ---

function wrapText(text: string, maxWidth: number): string[] {
    const lines: string[] = [];
    const rawLines = text.split('\n');

    for (const rawLine of rawLines) {
        if (!rawLine.trim()) {
            lines.push('');
            continue;
        }

        const words = rawLine.split(' ');
        let currentLine = words[0] || '';

        for (let i = 1; i < words.length; i++) {
            if (currentLine.length + 1 + words[i].length <= maxWidth) {
                currentLine += ' ' + words[i];
            } else {
                lines.push(currentLine);
                currentLine = words[i];
            }
        }
        lines.push(currentLine);
    }
    return lines;
}

function createBladeBox(text: string): string {
    const WIDTH = 60; 
    const CONTENT_WIDTH = WIDTH - 6; 
    const lines = wrapText(text, CONTENT_WIDTH);

    let out = `//${'='.repeat(WIDTH - 4)}\\\\\n`;
    out += `||${' '.repeat(WIDTH - 4)}||\n`;

    lines.forEach(line => {
        const padTotal = CONTENT_WIDTH - line.length;
        const padLeft = Math.floor(padTotal / 2);
        const padRight = padTotal - padLeft;
        out += `|| ${' '.repeat(padLeft)}${line}${' '.repeat(padRight)} ||\n`;
    });

    out += `||${' '.repeat(WIDTH - 4)}||\n`;
    out += `\\\\${'='.repeat(WIDTH - 4)}//`;
    return out;
}

function createMarkdownTable(headers: string[], rows: string[][]): string {
    if (headers.length === 0 && rows.length === 0) return '';
    let out = '';

    let maxCols = headers.length;
    rows.forEach(r => maxCols = Math.max(maxCols, r.length));

    while (headers.length < maxCols) headers.push('');

    if (headers.length > 0) {
        out += '| ' + headers.join(' | ') + ' |\n';
        out += '| ' + headers.map(() => '---').join(' | ') + ' |\n';
    } else if (rows.length > 0) {
        const first = rows.shift();
        if (first) {
             while (first.length < maxCols) first.push('');
             out += '| ' + first.join(' | ') + ' |\n';
             out += '| ' + first.map(() => '---').join(' | ') + ' |\n';
        }
    }

    rows.forEach(row => {
        while (row.length < maxCols) row.push('');
        out += '| ' + row.map(cell => cell.replace(/\|/g, '\\|').replace(/\n/g, '<br>')).join(' | ') + ' |\n';
    });

    return out;
}

function parseCookies(url: string, cookieString: string) {
    try {
        const u = new URL(url);
        return cookieString.split(';')
            .map(part => {
                const [key, ...vals] = part.trim().split('=');
                if(!key) return null;
                return {
                    name: key,
                    value: vals.join('='),
                    domain: u.hostname, 
                    path: '/'
                };
            })
            .filter(c => c !== null) as Array<{name: string, value: string, domain: string, path: string}>;
    } catch (e) {
        console.error("Cookie parse error", e);
        return [];
    }
}

