/**
 * Checks if HTML string contains the required selector.
 * If not, checks for common anti-bot signatures.
 */
function validateHtml(html: string, waitForSelector?: string): boolean {
    if (!waitForSelector) return true;

    const $ = cheerio.load(html);
    const selectors = waitForSelector.split(',').map(s => s.trim());
    let found = false;
    for (const s of selectors) {
        if ($(s).length > 0) {
            found = true;
            break;
        }
    }

    if (!found) {
        if (html.includes('Just a moment') || html.includes('Enable JavaScript') || html.includes('Verify you are human') || html.includes('Performing security verification')) {
            throw new Error("Cloudflare/Bot challenge detected (Page blocked)");
        }
        throw new Error(`Selector '${waitForSelector}' not found in response`);
    }
    return true;
}

async function fetchPlaywright(url: string, headless: boolean, waitForSelector?: string, cookies?: string, userAgent?: string): Promise<string> {
    const ua = userAgent || DEFAULT_USER_AGENT;

    // ARGS for stealth
    // Important: --disable-blink-features=AutomationControlled is key for Cloudflare
    const args = [
        '--disable-blink-features=AutomationControlled',
        '--no-sandbox',
        '--disable-setuid-sandbox',
        '--disable-infobars',
        '--window-position=0,0',
        '--disable-extensions',
    ];

    let browser = null;
    let context = null;
    let page = null;

    try {
        // --- CONTEXT CREATION STRATEGY ---
        if (headless) {
             // Tier 2: Ephemeral, Headless, Fast
             browser = await chromium.launch({ headless: true, args, ignoreDefaultArgs: ['--enable-automation'] });
             const domain = new URL(url).origin;
             context = await browser.newContext({
                userAgent: ua,
                viewport: { width: 1920, height: 1080 },
                locale: 'en-US',
                deviceScaleFactor: 1,
                timezoneId: 'America/New_York',
                javaScriptEnabled: true,
                extraHTTPHeaders: { 'Referer': domain, 'Origin': domain }
             });
        } else {
             // Tier 3: PERSISTENT PROFILE, Headful (The "Real User" Mode)
             // This stores cookies/localstorage in `data/browser_session`.
             // Once you pass a Cloudflare check here, it remembers you.
             console.log(`[Tier 3] Launching Persistent Context at: ${USER_DATA_DIR}`);
             context = await chromium.launchPersistentContext(USER_DATA_DIR, {
                headless: false,
                args,
                userAgent: ua,
                viewport: null, // Use actual window size
                ignoreDefaultArgs: ['--enable-automation'], // Hide "Chrome is being controlled by test software"
                locale: 'en-US',
             });
        }

        // --- APPLY STEALTH INJECTION ---
        // This is crucial. It runs before the page loads.
        await context.addInitScript(STEALTH_INJECTION);

        if (cookies) {
            const cookieList = parseCookies(url, cookies);
            if (cookieList.length > 0) await context.addCookies(cookieList);
        }

        // Get page
        page = headless ? await context.newPage() : (context.pages()[0] || await context.newPage());

        if (headless) {
            // Speed optimization for headless
            await page.route('**/*.{png,jpg,jpeg,gif,webp,svg,woff,woff2}', route => route.abort());
        }

        // Navigate
        // Increased timeout to 90s to allow for manual user interaction if needed
        await page.goto(url, { waitUntil: 'domcontentloaded', timeout: 90000 });

        // --- HUMAN BEHAVIOR SIMULATION (Headful Only) ---
        // Helps trigger "passive" turnstile checks
        if (!headless) {
            try {
                // Jiggle mouse
                await page.mouse.move(100, 100);
                await page.waitForTimeout(200);
                await page.mouse.move(200, 200, { steps: 10 });
                // Small scroll
                await page.mouse.wheel(0, 100);
            } catch (e) {}
        }

        // Wait for Content
        if (waitForSelector) {
            try {
                // Tier 2 gets 30s. Tier 3 gets 60s to allow user to solve captcha.
                const timeout = headless ? 30000 : 60000;
                await page.waitForSelector(waitForSelector, { state: 'attached', timeout });
                await page.waitForTimeout(1000); // Hydration wait
            } catch (e) {
                if (headless) throw new Error(`Timeout waiting for selector: ${waitForSelector}`);
                console.warn(`Headful timeout for ${waitForSelector}, grabbing current content anyway.`);
            }
        } else {
             await page.waitForTimeout(2000);
        }

        const content = await page.content();

        // Cleanup logic differs
        if (headless && browser) await browser.close();
        if (!headless && context) await context.close(); 

        return content;
    } catch (e: any) {
        // Ensure cleanup on error
        if (headless && browser) await browser.close();
        if (!headless && context) await context.close();
        throw e;
    }
}

export async function fetchHtml(url: string, waitForSelector?: string, cookies?: string, userAgent?: string): Promise<string> {
    const ua = userAgent || DEFAULT_USER_AGENT;

    // --- TIER 1: Static Fetch (Fastest) ---
    try {
        console.log(`[Tier 1] Static fetch: ${url}`);
        const headers: any = { 
            'User-Agent': ua,
            'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,image/webp,*/*;q=0.8',
            'Referer': new URL(url).origin
        };
        if (cookies) headers['Cookie'] = cookies;

        const res = await fetch(url, { headers });
        if (res.status === 403 || res.status === 429 || res.status === 503) throw new Error(`HTTP ${res.status} (Blocked)`);
        if (!res.ok) throw new Error(`HTTP ${res.status}`);

        const html = await res.text();
        validateHtml(html, waitForSelector); // Will throw if invalid
        return html;

    } catch (e: any) {
        console.log(`[Tier 1] Failed (${e.message}). escalating...`);
    }

    // --- TIER 2: Playwright Headless (Stealth) ---
    try {
        console.log(`[Tier 2] Headless Browser: ${url}`);
        const html = await fetchPlaywright(url, true, waitForSelector, cookies, userAgent);
        validateHtml(html, waitForSelector);
        return html;
    } catch (e: any) {
        console.log(`[Tier 2] Failed (${e.message}). escalating...`);
    }

    // --- TIER 3: Playwright Headful (Visible Window + Persistence) ---
    // This is the "Nuclear Option". It saves cookies to disk so once you pass, you pass forever.
    console.log(`[Tier 3] Visible Browser (Persistent): ${url}`);
    const html = await fetchPlaywright(url, false, waitForSelector, cookies, userAgent);

    // We don't catch here, if this fails, we let the error propagate to UI
    return html;
}

export function findProtocol(url: string, templates: ProtocolTemplate[]): ProtocolTemplate | undefined {
    const host = normalizeHost(url);
    return templates.find(t => {
        const tHost = normalizeHost(t.domain);
        return host === tHost || host.endsWith('.' + tHost);
    });
}

export async function extract(url: string, templates: ProtocolTemplate[]) {
    const protocol = findProtocol(url, templates);
    const html = await fetchHtml(
        url, 
        protocol ? protocol.contentSelector : undefined, 
        protocol?.cookies,
        protocol?.userAgent
    );

    const $ = cheerio.load(html);

    let title = '';
    let body = '';
    let hasRichContent = false;

    if (protocol) {
        let $root = null;
        try {
            const selectors = protocol.contentSelector.split(',').map(s => s.trim());
            for (const s of selectors) {
                const found = $(s).first();
                if (found.length > 0) {
                    $root = found;
                    break; 
                }
            }
        } catch (e) {
            throw new Error(`Invalid content selector: ${protocol.contentSelector}`);
        }

        if (!$root || $root.length === 0) {
            throw new Error(`Content selector '${protocol.contentSelector}' matched 0 elements.`);
        }

        $('script, style, iframe, noscript, svg, form').remove(); 
        $('div[id^="pf-"]').remove(); 
        $('[style*="display: none"]').remove();
        $('[style*="display:none"]').remove();
        $('[aria-hidden="true"]').remove();
        $('[hidden]').remove();
        $('.hidden').remove();

        if (protocol.removeSelectors) {
             protocol.removeSelectors.forEach(sel => {
                 try {
                     if (sel && sel.trim()) $(sel).remove();
                 } catch (e) {
                     console.warn(`Skipping invalid remove selector: ${sel}`);
                 }
             });
        }

        try {
            const $title = $(protocol.titleSelector).first();
            title = cleanText($title.text());
        } catch (e) {
            console.warn(`Invalid title selector: ${protocol.titleSelector}`);
        }

        const paras: string[] = [];
        $root.find('br').replaceWith(` ${BR_TOKEN} `); 

        const blockTags = [
            'p', 'div', 'blockquote', 'pre', 
            'h1', 'h2', 'h3', 'h4', 'h5', 'h6', 
            'li', 'article', 'section',
            'table'
        ];
        const selector = blockTags.join(', ');

        $root.find(selector).each((_, el) => {
            const $el = $(el);
            const tagName = el.tagName.toLowerCase();

            if (tagName === 'table') {
                 if ($el.parents('table').length > 0) return;

                 const rows: string[][] = [];
                 const headers: string[] = [];

                 $el.find('th').each((_, th) => {
                     headers.push(cleanText($(th).text()));
                 });

                 $el.find('tr').each((_, tr) => {
                     const cells: string[] = [];
                     const $tr = $(tr);
                     if ($tr.find('th').length > 0 && $tr.find('td').length === 0) return;

                     $tr.find('td').each((_, td) => {
                         const $td = $(td);
                         $td.find('p, div, li, h1, h2, h3, h4, h5').after(BR_TOKEN);
                         cells.push(cleanText($td.text()));
                     });
                     if (cells.length > 0) rows.push(cells);
                 });

                 const isSingleCell = (headers.length === 0 && rows.length === 1 && rows[0].length === 1);

                 if (isSingleCell) {
                     paras.push(createBladeBox(rows[0][0]));
                 } else {
                     paras.push(createMarkdownTable(headers, rows));
                 }
                 hasRichContent = true;
                 return;
            }

            if (tagName === 'blockquote') {
                if ($el.parents('table').length > 0) return;
                const qText = cleanText($el.text());
                paras.push(`> ${qText}`);
                hasRichContent = true;
                return;
            }

            if ($el.parents('table').length > 0) return;
            if ($el.find(selector).length > 0) return;

            const t = cleanText($el.text());
            if (t) paras.push(t);
        });

        // Pipeline: Clean Header -> Clean Footer -> Deduplicate
        const cleanedParas = cleanupHeader(paras, title);
        const fullyCleanedParas = cleanupFooter(cleanedParas, title);

        if (fullyCleanedParas.length === 0) {
            const raw = cleanText($root.text());
            if (raw.startsWith(title)) {
                body = raw.substring(title.length).trim();
            } else {
                body = raw;
            }
        } else {
            body = fullyCleanedParas.join('\n\n');
        }

    } else {
        $('script, style, iframe, noscript').remove();
        $('br').replaceWith(` ${BR_TOKEN} `);

        const titleEl = $('h1').first();
        title = cleanText(titleEl.text());

        const paras: string[] = [];
        $('p, div, blockquote, td, li').each((_, el) => {
             const $el = $(el);
             if ($el.find('p, div, blockquote, td, li').length > 0) return;
             const t = cleanText($el.text());
             if (t && t.length > 10) paras.push(t);
        });
        body = paras.join('\n\n');
        if (!body) throw new Error("No protocol found and auto-extraction failed.");
    }

    return {
        title,
        content: postProcessBody(body),
        url,
        matchedProtocol: protocol?.domain,
        hasRichContent
    };
}

export async function runDiagnostics(
    url: string, 
    domain: string, 
    titleSelector: string, 
    contentSelector: string, 
    removalSelectors: string[] = [],
    cookies?: string,
    userAgent?: string
): Promise<DiagnosticResult> {

    const html = await fetchHtml(url, contentSelector, cookies, userAgent);
    const $ = cheerio.load(html);
    const host = normalizeHost(url);

    $('script, style, iframe, noscript').remove();
    $('div[id^="pf-"]').remove();
    $('br').replaceWith(` ${BR_TOKEN} `);

    removalSelectors.forEach(s => { try { if(s.trim()) $(s).remove(); } catch (e) {} });

    let contentMatches = 0;
    let titleMatches = 0;
    let titleText = '';
    let pCount = 0;
    const paras: string[] = [];

    try {
        const $root = $(contentSelector).first();
        contentMatches = $root.length;

        if (contentMatches > 0) {
            const blockTags = ['p', 'div', 'blockquote', 'h1', 'h2', 'li', 'table'];
            const selector = blockTags.join(', ');

            $root.find(selector).each((_, el) => {
                const $el = $(el);

                if (el.tagName.toLowerCase() === 'table') {
                    if ($el.parents('table').length > 0) return;
                    paras.push("[TABLE/BOX DETECTED]");
                    pCount++;
                    return;
                }

                if ($el.find(selector).length > 0) return;
                if ($el.parents('table').length > 0) return;

                const t = cleanText($el.text());
                if (t) {
                    paras.push(t);
                    pCount++;
                }
            });
        }
    } catch (e) {
        return { host, titleMatches: 0, contentMatches: 0, paragraphCount: 0, titlePreview: '', contentPreview: '', error: `Invalid Content Selector` };
    }

    try {
        const $title = $(titleSelector).first();
        titleMatches = $title.length;
        titleText = cleanText($title.text());
    } catch (e) {
         return { host, titleMatches: 0, contentMatches, paragraphCount: 0, titlePreview: '', contentPreview: '', error: `Invalid Title Selector` };
    }

    let bodyPreview = '';
    if (paras.length > 0) {
        if (paras[0] === titleText) paras.shift();
        bodyPreview = paras.join('\n\n');
    } else {
        try { bodyPreview = cleanText($(contentSelector).first().text()); } catch {}
    }

    return {
        host,
        titleMatches,
        contentMatches,
        paragraphCount: pCount,
        titlePreview: titleText.substring(0, 120),
        contentPreview: bodyPreview.substring(0, 120),
    };
}

import * as cheerio from 'cheerio';
import { chromium } from 'playwright';
import { normalizeHost } from './domain.ts';
import path from 'path';
import { fileURLToPath } from 'url';
import type { ProtocolTemplate, DiagnosticResult } from '../types.ts';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

// CHANGED: Versioned directory V3 (Fresh Session)
const USER_DATA_DIR = path.join(__dirname, '..', 'data', 'browser_session_v3');

// Common User Agent to use across fetch and headless.
// Tier 3 will ignore this to use "Native Identity".
const DEFAULT_USER_AGENT = 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/126.0.0.0 Safari/537.36';

// Magic token for line breaks
const BR_TOKEN = '[[__BR__]]';

// ---------------------------------
// STEALTH INJECTION SCRIPT
// ---------------------------------
// Refined stealth script to prevent "AutomationControlled" leaks
const STEALTH_INJECTION = `
  // 1. Nuke WebDriver property completely
  delete Object.getPrototypeOf(navigator).webdriver;
  Object.defineProperty(navigator, 'webdriver', { get: () => undefined });

  // 2. Mock window.chrome
  if (!window.chrome) {
    window.chrome = {
      runtime: {},
      loadTimes: function() {},
      csi: function() {},
      app: {}
    };
  }

  // 3. Mock Permissions
  if (navigator.permissions) {
    const originalQuery = navigator.permissions.query;
    navigator.permissions.query = (parameters) => (
      parameters.name === 'notifications' ?
        Promise.resolve({ state: 'denied' }) :
        originalQuery(parameters)
    );
  }

  // 4. Mock Plugins
  Object.defineProperty(navigator, 'plugins', {
    get: () => {
      const p = [1, 2, 3, 4, 5];
      // @ts-ignore
      p.item = () => {};
      // @ts-ignore
      p.namedItem = () => {};
      return p;
    },
  });

  // 5. Mock Languages
  Object.defineProperty(navigator, 'languages', {
    get: () => ['en-US', 'en'],
  });
`;

// Standardized cleanup function
function cleanText(text: string): string {
  if (!text) return '';

  // 1. Replace newlines/tabs with space (standard HTML behavior)
  let t = text.replace(/[\r\n\t]+/g, ' ');

  // 2. Collapse multiple spaces
  t = t.replace(/\s+/g, ' ');

  // 3. Restore explicit line breaks
  t = t.split(BR_TOKEN).join('\n');

  // 4. Trim and remove odd artifacts
  return t.trim();
}

/**
 * Intelligent Header Trimming
 * Removes Titles, Dates, Author Names, and Metadata from the start of the content array.
 */
function cleanupHeader(paras: string[], title: string): string[] {
    let lines = [...paras];
    const t = cleanText(title).toLowerCase();

    // Safety: Only check the top few lines to avoid eating the story
    let checkLimit = 8;

    while (lines.length > 0 && checkLimit > 0) {
        checkLimit--;
        const line = cleanText(lines[0]);
        const lowLine = line.toLowerCase();

        // 1. Title Match (Exact, Fuzzy, or Contained)
        const isTitle = lowLine === t 
            || (t.length > 5 && lowLine.includes(t)) 
            || (lowLine.length > 5 && t.includes(lowLine));

        if (isTitle) {
            lines.shift();
            continue; // Keep checking next line
        }

        // 2. Date Detection
        const isDate = /(?:jan|feb|mar|apr|may|jun|jul|aug|sep|oct|nov|dec)[a-z]*[\s,.]+\d{1,2}(?:st|nd|rd|th)?[\s,.]+\d{4}/i.test(line)
            || /\d{4}[\-./]\d{2}[\-./]\d{2}/.test(line);

        if (isDate) {
            lines.shift();
            continue;
        }

        // 3. Metadata/Author Detection
        const isMetadata = line.length < 60 
            && !/[.!?]["']?$/.test(line)  // Ends with punctuation (optional quote)
            && !/^["“'‘]/.test(line)      // Starts with quote
            && /[a-z]/i.test(line)        // Has letters
            && !line.includes('“')        // Safety: Dialogue quotes inside
            && !line.includes('"');       // Safety: Dialogue quotes inside

        if (isMetadata) {
            lines.shift();
            continue;
        }

        // 4. Explicit "Posted by"
        if (/^(posted|written|published) by/i.test(line)) {
            lines.shift();
            continue;
        }

        // If nothing matched, we assume we hit the body.
        break;
    }

    return lines;
}

/**
 * Intelligent Footer Trimming
 */
function cleanupFooter(paras: string[], title: string): string[] {
    let lines = [...paras];
    const t = cleanText(title).toLowerCase();

    // Safety: Only check the bottom few lines
    let checkLimit = 10;

    while (lines.length > 0 && checkLimit > 0) {
        checkLimit--;
        const lastIndex = lines.length - 1;
        const line = cleanText(lines[lastIndex]);
        const lowLine = line.toLowerCase();

        // 1. Title Match
        const isTitle = lowLine === t 
            || (t.length > 5 && lowLine.includes(t)) 
            || (lowLine.length > 5 && t.includes(lowLine));

        if (isTitle) {
            lines.pop();
            continue;
        }

        // 2. Date Detection
        const isDate = /(?:jan|feb|mar|apr|may|jun|jul|aug|sep|oct|nov|dec)[a-z]*[\s,.]+\d{1,2}(?:st|nd|rd|th)?[\s,.]+\d{4}/i.test(line)
            || /\d{4}[\-./]\d{2}[\-./]\d{2}/.test(line);

        if (isDate) {
            lines.pop();
            continue;
        }

        // 3. Metadata/Author Detection
        const isMetadata = line.length < 60 
            && !/[.!?]["']?$/.test(line)
            && !/^["“'‘]/.test(line)
            && /[a-z]/i.test(line)
            && !line.includes('“') 
            && !line.includes('"');

        if (isMetadata) {
            lines.pop();
            continue;
        }

        // 4. Navigation/Social keywords
        if (/^(next|previous|prev) (chapter|part|episode)|(share|like|comment)/i.test(line)) {
            lines.pop();
            continue;
        }

        break;
    }

    return lines;
}

/**
 * Advanced Deduplication Strategy
 */
function deduplicateLines(text: string): string {
    let lines = text.split('\n').map(l => l.trim());

    // --- Phase 1: Neighbor Stutter Removal ---
    lines = lines.filter((line, i) => {
        if (!line) return i === 0 || lines[i-1] !== ''; 
        return i === 0 || line !== lines[i-1];
    });

    // --- Phase 2: Global Long-Paragraph Deduplication ---
    const seenLong = new Set<string>();
    const filteredBody: string[] = [];

    for (const line of lines) {
        if (!line) {
            filteredBody.push(line);
            continue;
        }
        if (line.length > 30) {
            if (seenLong.has(line)) continue; 
            seenLong.add(line);
        }
        filteredBody.push(line);
    }
    lines = filteredBody;

    // --- Phase 3: Smart Tail Trimming ---
    const frequency = new Map<string, number>();
    for (const line of lines) {
        if (line.length < 2) continue; 
        frequency.set(line, (frequency.get(line) || 0) + 1);
    }

    let endIndex = lines.length - 1;
    let cutCount = 0;

    while (endIndex >= 0) {
        const line = lines[endIndex];
        if (!line) {
            endIndex--;
            continue;
        }
        const count = frequency.get(line) || 1;
        if (count > 1) {
            endIndex--;
            cutCount++;
        } else {
            break; 
        }
    }

    if (cutCount < lines.length * 0.5) {
        lines = lines.slice(0, endIndex + 1);
    }

    return lines.join('\n');
}

function postProcessBody(body: string): string {
    const deduped = deduplicateLines(body);
    return deduped
        .replace(/\n{3,}/g, '\n\n') // Collapse 3+ newlines
        .trim();
}

function wrapText(text: string, maxWidth: number): string[] {
    const lines: string[] = [];
    const rawLines = text.split('\n');

    for (const rawLine of rawLines) {
        if (!rawLine.trim()) {
            lines.push('');
            continue;
        }

        const words = rawLine.split(' ');
        let currentLine = words[0] || '';

        for (let i = 1; i < words.length; i++) {
            if (currentLine.length + 1 + words[i].length <= maxWidth) {
                currentLine += ' ' + words[i];
            } else {
                lines.push(currentLine);
                currentLine = words[i];
            }
        }
        lines.push(currentLine);
    }
    return lines;
}

function createBladeBox(text: string): string {
    const WIDTH = 60; 
    const CONTENT_WIDTH = WIDTH - 6; 
    const lines = wrapText(text, CONTENT_WIDTH);

    let out = `//${'='.repeat(WIDTH - 4)}\\\\\n`;
    out += `||${' '.repeat(WIDTH - 4)}||\n`;

    lines.forEach(line => {
        const padTotal = CONTENT_WIDTH - line.length;
        const padLeft = Math.floor(padTotal / 2);
        const padRight = padTotal - padLeft;
        out += `|| ${' '.repeat(padLeft)}${line}${' '.repeat(padRight)} ||\n`;
    });

    out += `||${' '.repeat(WIDTH - 4)}||\n`;
    out += `\\\\${'='.repeat(WIDTH - 4)}//`;
    return out;
}

function createMarkdownTable(headers: string[], rows: string[][]): string {
    if (headers.length === 0 && rows.length === 0) return '';
    let out = '';

    let maxCols = headers.length;
    rows.forEach(r => maxCols = Math.max(maxCols, r.length));

    while (headers.length < maxCols) headers.push('');

    if (headers.length > 0) {
        out += '| ' + headers.join(' | ') + ' |\n';
        out += '| ' + headers.map(() => '---').join(' | ') + ' |\n';
    } else if (rows.length > 0) {
        const first = rows.shift();
        if (first) {
             while (first.length < maxCols) first.push('');
             out += '| ' + first.join(' | ') + ' |\n';
             out += '| ' + first.map(() => '---').join(' | ') + ' |\n';
        }
    }

    rows.forEach(row => {
        while (row.length < maxCols) row.push('');
        out += '| ' + row.map(cell => cell.replace(/\|/g, '\\|').replace(/\n/g, '<br>')).join(' | ') + ' |\n';
    });

    return out;
}

function parseCookies(url: string, cookieString: string) {
    try {
        const u = new URL(url);
        return cookieString.split(';')
            .map(part => {
                const [key, ...vals] = part.trim().split('=');
                if(!key) return null;
                return {
                    name: key,
                    value: vals.join('='),
                    domain: u.hostname, 
                    path: '/'
                };
            })
            .filter(c => c !== null) as Array<{name: string, value: string, domain: string, path: string}>;
    } catch (e) {
        console.error("Cookie parse error", e);
        return [];
    }
}

